#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,ans=0,a,b,c;
    cin>>n;
    a=n/100,b=n/10%10,c=n%10;
    while(a!=4 || b!=9 || c!=5){
        if(a>b)swap(a,b);
        if(a>c)swap(a,c);
        if(b>c)swap(b,c);
        int tmp=c*100+b*10+a-a*100-b*10-c;
        a=tmp/100,b=tmp/10%10,c=tmp%10;
        ans++;
    }
    cout<<ans;
    return 0;
}
